for (let i = 0; i < $input.all().length; i++) {
  let traceData = $input.all()[i].json.compromised_log || "";
  let threatType = $input.all()[i].json.threat_actor || "UNKNOWN";

  // Isolate the mutated locked extension filename directly via split array loops
  let isolatedTarget = "Unknown_Asset";
  if (traceData.includes("TARGET:")) {
     let segments = traceData.split("|");
     for (let element of segments) {
       if (element.includes("TARGET:")) {
         isolatedTarget = element.split(":")[1].trim();
         break;
       }
     }
  }

  // Automatically compile system remediation actions to kill the malware process ID
  $input.all()[i].json.remediation_kill_cmd = `sudo pkill -f ${threatType}`;
  $input.all()[i].json.quarantine_target = isolatedTarget;
}
return $input.all();
